import {chrome} from '../../utils/polyfill.ts';
import {msgPromptNativeMsg, msgRemoveNativeMessaging} from '../../utils/native-messaging.ts';
import {translateText} from '../../utils/locales.ts';
import {truncate, parseParams} from '../../utils/utils';
import {MSG_IS_NEEDING_NATIVE_MSG, MSG_SETTINGS_SET, SETTING_NATIVE_MESSAGING} from './app-consts';

const mbbp = {};

//@ts-ignore
const useLogging = (ENVIRONMENT == "development");

mbbp.templateParameters = () => {
    let params = parseParams(window.location.search);
    return params;
};

mbbp.params = mbbp.templateParameters();

document.addEventListener("DOMContentLoaded", function() {
    // re-initialize the popup after each window resize so that the tooltip still works when users hover
    window.addEventListener('resize', () => {
        $('#mbbgb-inf').popup({
            inline: true,
            hoverable: true,
            lastResort: 'bottom center'
        });
    });

    fillInTemplateText();
    updateBlockedUrlText();
    //malwarebytes is not defined here (insecure) so we need to send a message to it
    fillInTemplateActions();
    chrome.runtime.sendMessage(
        {
            type: MSG_IS_NEEDING_NATIVE_MSG,
            parameters: {source: "contentControlBlockPage"}
        },
        (resp) => {
            if (chrome.runtime.lastError) {
                console.error(
                    "MBN: Chrome Runtime Failure: ",
                    chrome.runtime.lastError
                );
            }
            if (resp && resp.needsIt) {
                $('#mbbgb-header-footer').animate(
                    {'max-height': '100%', "opacity": 1}, 800
                );
                attachNmEvents();
            }
        }
    );
});

function fillInTemplateText() {
    translateText([
        {id: "blocked-by-title", msg: "blockedByTitle"},
        {id: "block-reason", msg: "contentControlWebsiteBlockHeader"},
        {id: "block-explanation", msg: "contentControlWebsiteBlockExplanation"},
        {id: "block-alert-text", msg: "contentControlBlockAlertText"},
        {id: "block-alert-link", msg: "mv3WebsiteBlockMalwarebytesSupport"},
        {id: "block-go-back", msg: "mv3WebsiteBlockGoBack"},
        {id: "block-learn-more", msg: "mv3WebsiteBlockLearnMore"},
        {id: "block-learn-more-link", msg: "mv3WebsiteBlockLearnMoreLink"},
    ]);
}

function updateBlockedUrlText() {
    const websiteBlockedSpan = document.querySelector('#block-url');
    const host = truncate(mbbp.params.url);
    websiteBlockedSpan.textContent = host;
}

function fillInTemplateActions() {
    document.getElementById('go-back').addEventListener('click', handleBackButton);
}

function handleBackButton() {
    if (mbbp.params.prevUrl && mbbp.params.prevUrl.length > 0) {
        return window.location.replace(mbbp.params.prevUrl);
    }

    if (window.history.length > 1) {
        return window.history.go(-1); // only -1 needed (not -2) it treats the malicious and the block as one entry now
    }

    // If we didn't open the block page in the same tab, we have to hunt for it
    let url;
    try {
        url = new URL(mbbp.params.referrer);
    } catch (e) {
        // ignore
    }

    chrome.tabs.query({currentWindow: true, active: true}, (activeTabs) => {
        if (url) {
            chrome.tabs.query(
                {currentWindow: true, url: `${url.origin}/*`},
                (tabs) => {
                    if (tabs[0].index) {
                        chrome.tabs.highlight({tabs: tabs[0].index}, () => {
                            if (activeTabs[0].id) {
                                chrome.tabs.remove(activeTabs[0].id);
                            }
                        });
                    }
                }
            );
        } else if (activeTabs[0].id) {
            chrome.tabs.remove(activeTabs[0].id);
        }
    });
}

const attachNmEvents = () => {
    translateText([
        {id: "nm-header", msg: "nativeMessagingHeader2"},
        {id: "nm-message", msg: "nativeMessagingMessage2"},
        {id: "decline-nm", msg: "buttonOptOut"},
        {id: "accept-nm", msg: "buttonOptIn"}
    ]);

    [
        {id: "accept-nm", val: true},
        {id: "decline-nm", val: false},
    ].forEach(({id, val}) => {
        document.getElementById(id).addEventListener("click", async () => {
            let resp = val ? await msgPromptNativeMsg() : await msgRemoveNativeMessaging();

            chrome.runtime.sendMessage(
                {
                    type: MSG_SETTINGS_SET,
                    payload: {[SETTING_NATIVE_MESSAGING]: resp},
                },
                (response) => {
                    if (!response || response.error) {
                        console.error(response && response.error);
                    } else {
                        useLogging && console.debug(
                            `PR: Turned ${
                                resp ? "on" : "off"
                            } Native Messaging`
                        );
                    }
                    document.getElementById(
                        "mbbgb-header-footer"
                    ).style.display = 'none';
                }
            );
        });
    });
};
